const PILL_GAP = 22;
const PILL_H = 32;
const PILL_R = PILL_H / 2;
const DOT_R = 5;
const TEXT_OFFSET = DOT_R * 2 + 10;
const MAP_PIN_LOGO = BRAND.favicon;
const MAP_PIN_LOGO_SIZE = 22;
const MAP_PIN_LOGO_RADIUS = MAP_PIN_LOGO_SIZE / 2;

const HERO_MAP_CITIES = [
  { key: "jaffna", label: "Jaffna", pillSide: "right" as const, pillW: 118 },
  { key: "vavuniya", label: "Vavuniya", pillSide: "left" as const, pillW: 138 },
  { key: "puttalam", label: "Puttalam", pillSide: "left" as const, pillW: 138 },
  { key: "colombo", label: "Colombo", pillSide: "left" as const, pillW: 138 },
  { key: "galle", label: "Galle", pillSide: "right" as const, pillW: 108 },
] as const;

/** West-coast pins: flip labels to the right on desktop so pills are not clipped. */
const DESKTOP_PILL_SIDE: Partial<
  Record<(typeof HERO_MAP_CITIES)[number]["key"], "left" | "right">
> = {
  puttalam: "right",
  colombo: "right",
};

function useHeroMapDesktopLayout() {
  const [isDesktop, setIsDesktop] = useState(false);

  useEffect(() => {
    const media = window.matchMedia("(min-width: 1024px)");
    const sync = () => setIsDesktop(media.matches);
    sync();
    media.addEventListener("change", sync);
    return () => media.removeEventListener("change", sync);
  }, []);

  return isDesktop;
}

function pillXForPin(cx: number, pillW: number, side: "left" | "right") {
  return side === "right" ? cx + PILL_GAP : cx - pillW - PILL_GAP;
}

function CityPin({
  cx,
  cy,
  label,
  pillX,
  pillW,
}: {
  cx: number;
  cy: number;
  label: string;
  pillX: number;
  pillW: number;
}) {
  const pillY = cy - PILL_H / 2;
  const dotCx = pillX + DOT_R + 8;
  const textX = pillX + TEXT_OFFSET;
  const pillOnRight = pillX > cx;
  const lineEndX = pillOnRight ? pillX : pillX + pillW;

  return (
    <g>
      <line
        x1={cx}
        y1={cy}
        x2={lineEndX}
        y2={cy}
        stroke="rgba(245, 166, 35, 0.45)"
        strokeWidth={1.5}
        strokeDasharray="5 4"
      />
      <circle
        cx={cx}
        cy={cy}
        r={16}
        fill="rgba(245, 166, 35, 0.15)"
        stroke="rgba(245, 166, 35, 0.55)"
        strokeWidth={1.5}
      >
        <animate attributeName="r" values="16;42" dur="2.4s" repeatCount="indefinite" />
        <animate attributeName="opacity" values="1;0" dur="2.4s" repeatCount="indefinite" />
      </circle>
      <circle
        cx={cx}
        cy={cy}
        r={MAP_PIN_LOGO_RADIUS + 3}
        fill="#ffffff"
        stroke="#f5a623"
        strokeWidth={2}
      />
      <image
        href={MAP_PIN_LOGO}
        x={cx - MAP_PIN_LOGO_RADIUS}
        y={cy - MAP_PIN_LOGO_RADIUS}
        width={MAP_PIN_LOGO_SIZE}
        height={MAP_PIN_LOGO_SIZE}
        preserveAspectRatio="xMidYMid meet"
      />
      <rect
        x={pillX}
        y={pillY}
        rx={PILL_R}
        ry={PILL_R}
        width={pillW}
        height={PILL_H}
        fill="rgba(28, 37, 71, 0.95)"
        stroke="#f5a623"
        strokeWidth={1.5}
      />
      <circle cx={dotCx} cy={cy} r={DOT_R} fill="#f5a623" />
      <text
        x={textX}
        y={cy}
        fill="#ffffff"
        fontFamily="Inter, Outfit, system-ui, sans-serif"
        fontSize={18}
        fontWeight={700}
        letterSpacing={1}
        dominantBaseline="middle"
      >
        {label}
      </text>
    </g>
  );
}

/** Sri Lanka map with islandwide city markers behind the founder portrait. */
export function HeroFounderIslandMap() {
  const isDesktop = useHeroMapDesktopLayout();

  return (
    <div className="hero-founder-map-backdrop" aria-hidden>
      <svg
        viewBox={HERO_MAP_VIEWBOX}
        className="hero-founder-island-map-svg"
        preserveAspectRatio="xMidYMid meet"
        overflow="visible"
        xmlns="http://www.w3.org/2000/svg"
      >
        <path d={ISLAND_PATH} className="map-island-path" />

        {HERO_MAP_CITIES.map(({ key, label, pillSide, pillW }) => {
          const { x: cx, y: cy } = HERO_FOUNDER_MAP_MARKERS[key];
          const side =
            isDesktop && DESKTOP_PILL_SIDE[key] ? DESKTOP_PILL_SIDE[key]! : pillSide;
          return (
            <CityPin
              key={key}
              cx={cx}
              cy={cy}
              label={label}
              pillX={pillXForPin(cx, pillW, side)}
              pillW={pillW}
            />
          );
        })}
      </svg>
    </div>
  );
}
